1	/**
2	 * Onboarding state shape and the discriminated union of actions the reducer
3	 * accepts. The reducer is the single mutation point; every effect/component
4	 * dispatches into it. Keep this file authoritative for what the flow
5	 * remembers and how it can change.
6	 */
7	
8	import type {
9	  OnboardingStage,
10	  PersonalizationData,
11	  StagePayloads,
12	} from "../types/websocket";
13	
14	/**
15	 * Linear stage queue rendered by the page. Each stage advances forward only,
16	 * driven by either a user action (ack / confirm) or a backend "no data, skip"
17	 * signal. `getStage` walks the queue once per render — components should
18	 * never compute this themselves.
19	 */
20	export type Stage =
21	  | "questions"
22	  | "focus"
23	  | "processing"
24	  | "revealWriting"
25	  | "revealTodos"
26	  | "workflows"
27	  | "platforms"
28	  | "chat";
29	
30	export interface OnboardingState {
31	  /** Answered Q&A keyed by FIELD_NAMES (name, profession, gmail, focus). */
32	  responses: Record<string, string>;
33	  /** Index into `questions[]`; equals questions.length once Q&A is finished. */
34	  questionIndex: number;
35	  /** In-flight text input value for the active text question. */
36	  draftText: string;
37	  /** In-flight Autocomplete value for the profession question. */
38	  draftProfession: string | null;
39	
40	  /** Latest server-side personalization snapshot (REST + WS-merged). */
41	  server: PersonalizationData | null;
42	
43	  /**
44	   * Live status text from the backend, scoped per stage so a late
45	   * progress event from one stage cannot bleed into the visible label of
46	   * another. Keyed by the emitting `OnboardingStage`.
47	   */
48	  progressByStage: Partial<Record<OnboardingStage, string>>;
49	  /** Set of pipeline stages that have emitted a completion event. */
50	  completedStages: Set<OnboardingStage>;
51	
52	  /** User confirmed the writing-style reveal card. */
53	  ackedWritingStyle: boolean;
54	  /** User confirmed (or skipped) the todos reveal card. */
55	  ackedTodos: boolean;
56	
57	  /** User clicked "Understood" on the workflows reveal card. */
58	  workflowsConfirmed: boolean;
59	  /** User finished the platform-connect step — either connected or skipped. */
60	  platformsConfirmed: boolean;
61	  /** Messaging platform the user linked during the platforms stage, if any. */
62	  connectedPlatform: string | null;
63	
64	  /** Pending todo to auto-send into the chat conversation once it's ready. */
65	  todoExecutionMessage: string | null;
66	
67	  /** POST /onboarding failed; the processing composer offers a retry. */
68	  submissionError: boolean;
69	  /** Restart in progress — UI is locked while the server `/reset` runs. */
70	  isRestarting: boolean;
71	}
72	
73	export type Action =
74	  /** Live-update the active text question's draft input. */
75	  | { type: "draftText"; value: string }
76	  /** Live-update the profession Autocomplete draft. */
77	  | { type: "draftProfession"; value: string | null }
78	  /** User submitted an answer; advances `questionIndex`. */
79	  | { type: "answer"; field: string; value: string }
80	  /** POST /onboarding failed; arms the retry composer. */
81	  | { type: "submitError" }
82	  /** User clicked retry on the submission error composer. */
83	  | { type: "retrySubmit" }
84	  /** Full personalization snapshot from REST (poll or initial fetch). */
85	  | { type: "serverSnapshot"; data: PersonalizationData }
86	  /** Partial patch from a WS stage event. */
87	  | {
88	      type: "serverPatch";
89	      patch: Partial<PersonalizationData>;
90	    }
91	  /**
92	   * Live status string emitted by a specific backend stage. Stored under
93	   * the stage that emitted it so the UI can scope display per step.
94	   */
95	  | { type: "progress"; stage: OnboardingStage; message: string }
96	  /** A backend stage finished — used to drive the processing checklist. */
97	  | { type: "stageComplete"; stage: OnboardingStage }
98	  /** User confirmed the writing-style reveal card. */
99	  | { type: "ackWriting" }
100	  /** User confirmed (or skipped) the todos reveal card. */
101	  | { type: "ackTodos" }
102	  /** User clicked "Understood" on the workflows reveal card. */
103	  | { type: "confirmWorkflows" }
104	  /** User finished the platform-connect popup flow. */
105	  | { type: "platformConnected"; platform: string }
106	  /** User skipped the platform-connect step without picking a platform. */
107	  | { type: "skipPlatforms" }
108	  /** User clicked Run on a todo; queues the message for the chat stage. */
109	  | { type: "executeTodo"; message: string }
110	  /** Chat stage consumed the pending todo execution message. */
111	  | { type: "clearTodoExecutionMessage" }
112	  /** Restart kicked off — flips state back to initial and locks UI. */
113	  | { type: "restartStart" }
114	  /** Server `/reset` settled (success or fail); unlocks UI. */
115	  | { type: "restartDone" }
116	  /** Hydrate from sessionStorage (or backend resume) on mount. */
117	  | { type: "hydrate"; partial: Partial<OnboardingState> }
118	  /** Hard reset to `initialState` (test/debug). */
119	  | { type: "reset" };
120	
121	export type StagePayload<K extends OnboardingStage> = StagePayloads[K];
