    >
      <Accordion
        variant="light"
        className="px-0"
        onSelectionChange={(keys) => {
          const set = keys as Set<string | number>;
          setIsOpen(set.size > 0);
        }}
        itemClasses={{
          base: "px-0",
          trigger: "px-3 py-2 rounded-2xl data-[hover=true]:bg-zinc-700/40",
          titleWrapper: "py-0",
          content: "px-3 pt-2 pb-3",
        }}
      >
        <AccordionItem
          key={itemKey}
          aria-label={title}
          title={
            <div className="flex items-center gap-2">
