1	/**
2	 * `platforms` stage. Shows the Telegram / WhatsApp / Discord picker so the
3	 * user can pick a messaging platform to receive briefings on. The stage
4	 * advances when the user either connects a platform (dispatch
5	 * `platformConnected`) or clicks Skip (dispatch `skipPlatforms`).
6	 */
7	
8	"use client";
9	
10	import * as m from "motion/react-m";
11	import type { Dispatch } from "react";
12	import { useCallback, useEffect, useRef, useState } from "react";
13	import ChatBubbleBot from "@/features/chat/components/bubbles/bot/ChatBubbleBot";
14	import { apiService } from "@/lib/api/service";
15	import { useUserStore } from "@/stores/userStore";
16	import { FIELD_NAMES } from "../../constants";
17	import { BOT_BUBBLE_DEFAULTS } from "../../constants/bubbleDefaults";
18	import { MOTION_FADE_UP } from "../../constants/motion";
19	import type { PlatformPreviewPlatform } from "../../constants/platformPreviewMessages";
20	import type { Action, OnboardingState } from "../../state/types";
21	import { OnboardingPlatformConnect } from "../OnboardingPlatformConnect";
22	import { OnboardingPlatformPreview } from "../OnboardingPlatformPreview";
23	
24	interface PlatformsProps {
25	  state: OnboardingState;
26	  dispatch: Dispatch<Action>;
27	}
28	
29	export function Platforms({ state, dispatch }: PlatformsProps) {
30	  const popupCleanupRef = useRef<(() => void) | null>(null);
31	  const [hoveredPlatform, setHoveredPlatform] =
32	    useState<PlatformPreviewPlatform | null>(null);
33	
34	  const profession = state.responses[FIELD_NAMES.PROFESSION];
35	  const onboardingName = state.responses[FIELD_NAMES.NAME];
36	  const storeName = useUserStore((s) => s.name);
37	  const storeAvatar = useUserStore((s) => s.profilePicture);
38	  const userName = onboardingName || storeName;
39	  const userAvatar = storeAvatar;
40	
41	  const connectPlatform = useCallback(
42	    async (platform: string) => {
43	      popupCleanupRef.current?.();
44	      popupCleanupRef.current = null;
45	
46	      const finish = () => {
47	        dispatch({ type: "platformConnected", platform });
48	      };
49	
50	      try {
51	        const response = await apiService.get<{
52	          auth_url: string | null;
53	          auth_type: string;
54	          instructions: string | null;
55	          action_link: string | null;
56	        }>(`/platform-links/${platform.toLowerCase()}/connect`, {
57	          silent: true,
58	        });
59	
60	        if (response.auth_url) {
61	          const width = 600;
62	          const height = 700;
63	          const left = window.screenX + (window.innerWidth - width) / 2;
64	          const top = window.screenY + (window.innerHeight - height) / 2;
65	
66	          const popup = window.open(
