1	/**
2	 * Full-screen layout wrapper for the onboarding page. Three regions: top
3	 * progress bar, scrollable content (caller-supplied children), and an
4	 * optional pinned composer at the bottom. Auto-scrolls the content region
5	 * to bottom whenever stage- or content-bearing state changes.
6	 */
7	
8	"use client";
9	
10	import type { ReactNode } from "react";
11	import { useEffect, useMemo, useRef } from "react";
12	import BlurStack, { type BlurLayer } from "@/components/ui/blur-stack";
13	import { getProgress, PROGRESS_TOTAL_STEPS } from "../state/derive";
14	import type { OnboardingState, Stage } from "../state/types";
15	import { OnboardingProgress } from "./OnboardingProgress";
16	
17	// Heavy-blur-at-top config — mirror of the default heavy-at-bottom stack.
18	const TOP_BLUR_CONFIG: BlurLayer[] = [
19	  { blur: 0.5, maskStops: [62.5, 75, 87.5, 100], zIndex: 1 },
20	  { blur: 1, maskStops: [50, 62.5, 75, 87.5], zIndex: 2 },
21	  { blur: 2, maskStops: [37.5, 50, 62.5, 75], zIndex: 3 },
22	  { blur: 4, maskStops: [25, 37.5, 50, 62.5], zIndex: 4 },
23	  { blur: 8, maskStops: [12.5, 25, 37.5, 50], zIndex: 5 },
24	  { blur: 16, maskStops: [0, 12.5, 25, 37.5], zIndex: 6 },
25	  { blur: 32, maskStops: [0, 0, 12.5, 25], zIndex: 7 },
26	  { blur: 64, maskStops: [0, 0, 0, 12.5], zIndex: 8 },
27	];
28	
29	interface OnboardingShellProps {
30	  state: OnboardingState;
31	  stage: Stage;
32	  onRestart: () => void;
33	  children: ReactNode;
34	  composer?: ReactNode;
35	  /**
36	   * When true, widens the content column so the in-place onboarding chat
37	   * stream has enough horizontal room for ChatBubbleBot + tool cards
38	   * (mail list, etc.) without right-cropping.
39	   */
40	  wide?: boolean;
41	}
42	
43	/**
44	 * Single string fingerprint of "what's on screen". Used as a useEffect dep so
45	 * scroll-to-bottom fires once per content change instead of needing 7 deps.
46	 */
47	function getContentFingerprint(state: OnboardingState, stage: Stage): string {
48	  const b = state.server;
49	  // Concat every active progress slot — any change to any stage's status_text
50	  // should re-trigger the scroll-to-bottom effect.
51	  const progress = Object.values(state.progressByStage).join("");
52	  return [
53	    stage,
54	    state.questionIndex,
55	    progress,
56	    state.completedStages.size,
57	    state.ackedWritingStyle ? 1 : 0,
58	    state.ackedTodos ? 1 : 0,
59	    state.workflowsConfirmed ? 1 : 0,
60	    state.platformsConfirmed ? 1 : 0,
61	    state.connectedPlatform ?? "",
62	    b?.writing_style?.style_summary ?? "",
63	    b?.onboarding_todos?.length ?? 0,
64	    b?.suggested_workflows?.length ?? 0,
65	    b?.first_message_conversation_id ?? "",
66	    state.todoExecutionMessage ?? "",
67	  ].join("|");
68	}
69	
70	export function OnboardingShell({
71	  state,
72	  stage,
73	  onRestart,
74	  children,
75	  composer,
76	  wide = false,
77	}: OnboardingShellProps) {
78	  const scrollRef = useRef<HTMLDivElement>(null);
79	  const progressStep = getProgress(state, stage);
80	  const fingerprint = useMemo(
81	    () => getContentFingerprint(state, stage),
82	    [state, stage],
83	  );
84	
85	  useEffect(() => {
86	    scrollRef.current?.scrollTo({
87	      top: scrollRef.current.scrollHeight,
88	      behavior: "smooth",
89	    });
90	  }, [fingerprint]);
91	
92	  return (
93	    <div className="fixed inset-0 z-50 flex flex-col bg-primary-bg backdrop-blur-2xl">
94	      <div
95	        aria-hidden
96	        className="pointer-events-none absolute inset-0 z-0 bg-center bg-cover opacity-40"
97	        style={{
98	          backgroundImage: "url('/images/wallpapers/bands_gradient_black.png')",
99	        }}
100	      />
101	      <OnboardingProgress
102	        currentStep={progressStep}
103	        totalSteps={PROGRESS_TOTAL_STEPS}
104	        onRestart={onRestart}
105	        isRestarting={state.isRestarting}
106	      />
107	
108	      <div
109	        ref={scrollRef}
110	        className="relative z-10 flex-1 overflow-y-auto px-4 pt-20"
111	      >
112	        <div
113	          className={`relative mx-auto w-full pb-32 ${
114	            wide ? "max-w-(--breakpoint-xl)" : "max-w-2xl"
115	          }`}
116	        >
117	          {children}
118	        </div>
119	      </div>
120	
121	      <BlurStack
122	        className="pointer-events-none fixed top-0 right-0 left-0 z-20 h-24"
123	        config={TOP_BLUR_CONFIG}
124	      />
125	      <BlurStack className="pointer-events-none fixed right-0 bottom-0 left-0 z-20 h-24" />
126	
127	      {composer && (
128	        <div className="fixed inset-x-0 bottom-0 z-30 mx-auto w-full max-w-lg pb-3">
129	          {composer}
130	        </div>
131	      )}
132	    </div>
133	  );
134	}

