1	/**
2	 * Top-level orchestrator page for the onboarding flow. Uses `useOnboarding`
3	 * to get the derived stage, then picks a `stageContent` and a `composer`
4	 * for that stage. Stage-driven swapping keeps each stage's logic isolated;
5	 * shared transcript + progress chrome live in `OnboardingShell` /
6	 * `MessagesRegion`. `skipAutoRedirect` keeps the chat stage rendered here
7	 * instead of redirecting into the standalone `/c/:id` route.
8	 */
9	
10	"use client";
11	
12	import { AnimatePresence } from "motion/react";
13	import * as m from "motion/react-m";
14	import { useState } from "react";
15	import { CompletedStagesTimeline } from "@/features/onboarding/components/CompletedStagesTimeline";
16	import { MessagesRegion } from "@/features/onboarding/components/MessagesRegion";
17	import { OnboardingIntro } from "@/features/onboarding/components/OnboardingIntro";
18	import { OnboardingShell } from "@/features/onboarding/components/OnboardingShell";
19	import {
20	  Chat,
21	  ChatComposer,
22	  FocusComposer,
23	  Platforms,
24	  ProcessingComposer,
25	  QuestionsComposer,
26	  RevealTodos,
27	  RevealWritingStyle,
28	  RevealWritingStyleComposer,
29	  useChatStage,
30	  Workflows,
31	  WorkflowsComposer,
32	} from "@/features/onboarding/components/stages";
33	import { EASE_OUT_QUART } from "@/features/onboarding/constants/motion";
34	import { useOnboarding } from "@/features/onboarding/hooks/useOnboarding";
35	
36	const INTRO_FADE_IN = {
37	  initial: { opacity: 0, filter: "blur(12px)" },
38	  animate: { opacity: 1, filter: "blur(0px)" },
39	  transition: { duration: 0.6, ease: EASE_OUT_QUART },
40	} as const;
41	
42	const INTRO_SEEN_KEY = "gaia.onboarding.introSeen";
43	
44	function hasSeenIntro(): boolean {
45	  if (typeof window === "undefined") return false;
46	  try {
47	    return window.sessionStorage.getItem(INTRO_SEEN_KEY) === "1";
48	  } catch {
49	    return false;
50	  }
51	}
52	
53	function markIntroSeen(): void {
54	  try {
55	    window.sessionStorage.setItem(INTRO_SEEN_KEY, "1");
56	  } catch {
57	    // sessionStorage unavailable (private mode, etc.) — silently skip.
58	  }
59	}
60	
61	export default function Onboarding() {
62	  const { state, stage, dispatch, restart } = useOnboarding({
63	    skipAutoRedirect: true,
64	  });
65	  const [introDone, setIntroDone] = useState<boolean>(hasSeenIntro);
66	
67	  const handleRestart = () => {
68	    try {
69	      window.sessionStorage.removeItem(INTRO_SEEN_KEY);
70	    } catch {}
71	    setIntroDone(false);
72	    return restart();
73	  };
74	
75	  const handleIntroComplete = () => {
76	    markIntroSeen();
77	    setIntroDone(true);
78	  };
79	
80	  const chat = useChatStage(state, dispatch);
81	
82	  const stageContent = (() => {
83	    switch (stage) {
84	      case "questions":
85	      case "focus":
86	      case "processing":
87	        return null;
88	      case "revealWriting":
89	        return <RevealWritingStyle state={state} />;
90	      case "revealTodos":
91	        return <RevealTodos state={state} dispatch={dispatch} chat={chat} />;
92	      case "workflows":
93	        return <Workflows state={state} dispatch={dispatch} />;
94	      case "platforms":
95	        return <Platforms state={state} dispatch={dispatch} />;
96	      case "chat":
97	        return <Chat state={state} />;
98	    }
99	  })();
100	
101	  const composer = (() => {
102	    switch (stage) {
103	      case "questions":
104	        return <QuestionsComposer state={state} dispatch={dispatch} />;
105	      case "focus":
106	        return <FocusComposer state={state} dispatch={dispatch} />;
107	      case "processing":
108	        return <ProcessingComposer state={state} dispatch={dispatch} />;
109	      case "revealWriting":
110	        return <RevealWritingStyleComposer state={state} dispatch={dispatch} />;
111	      case "revealTodos":
112	        return null;
113	      case "workflows":
114	        return <WorkflowsComposer state={state} dispatch={dispatch} />;
115	      case "platforms":
116	        return null;
117	      case "chat":
118	        return <ChatComposer state={state} />;
119	    }
120	  })();
121	
122	  const wrappedComposer = introDone ? (
123	    <m.div {...INTRO_FADE_IN}>{composer}</m.div>
124	  ) : null;
125	
126	  return (
127	    <>
128	      <OnboardingShell
129	        state={state}
130	        stage={stage}
131	        onRestart={handleRestart}
132	        composer={wrappedComposer}
133	        wide={state.todoExecutionStarted}
134	      >
135	        {introDone ? (
136	          <m.div {...INTRO_FADE_IN}>
137	            <MessagesRegion state={state} stage={stage} />
138	            <CompletedStagesTimeline state={state} chat={chat} />
139	            {stageContent}
140	          </m.div>
141	        ) : null}
142	      </OnboardingShell>
143	      <AnimatePresence>
144	        {!introDone && <OnboardingIntro onComplete={handleIntroComplete} />}
145	      </AnimatePresence>
146	    </>
147	  );
148	}
